const target = parseFloat($env.ACTIVATION_TARGET_PCT || 40);
const cohorts = $input.all().map(i => {
  const d = i.json;
  const n = parseInt(d.new_users || 1);
  const a7 = (parseInt(d.activated_7d||0)/n*100).toFixed(1);
  const a14 = (parseInt(d.activated_14d||0)/n*100).toFixed(1);
  const a30 = (parseInt(d.activated_30d||0)/n*100).toFixed(1);
  const is_below_target = parseFloat(a14) < target;
  return { ...d, activation_7d_pct: parseFloat(a7), activation_14d_pct: parseFloat(a14), activation_30d_pct: parseFloat(a30), is_below_target };
}).sort((a, b) => b.activation_14d_pct - a.activation_14d_pct);
const below = cohorts.filter(c => c.is_below_target);
const avg14 = cohorts.length > 0 ? (cohorts.reduce((s,c)=>s+c.activation_14d_pct,0)/cohorts.length).toFixed(1) : 0;
return [{ json: { week: new Date().toISOString().slice(0,10), target_pct: target, avg_14d_activation: parseFloat(avg14), cohorts, below_target_count: below.length, below_target: below } }];

